import * as fs from 'fs';
import * as path from 'path';

export async function doStep(i: number): Promise<void> {
  const logPath = '/workspace/progress.log';
  fs.appendFileSync(logPath, `step ${i}\n`);
}

import { proxyActivities, defineQuery, setHandler, sleep } from '@temporalio/workflow';
import type * as activities from './activities';

const { doStep } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30s',
});

export const getProgressQuery = defineQuery<{ progress: number; currentStep: number; total: number }>('getProgress');

export async function ProgressWorkflow(totalSteps: number): Promise<{ progress: number; currentStep: number; total: number }> {
  let currentStep = 0;
  let progress = 0;

  setHandler(getProgressQuery, () => ({
    progress,
    currentStep,
    total: totalSteps,
  }));

  for (let i = 1; i <= totalSteps; i++) {
    await doStep(i);
    currentStep = i;
    progress = i / totalSteps;
    await sleep('1s');
  }

  return {
    progress,
    currentStep,
    total: totalSteps,
  };
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error('Missing environment variables');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    metadata: {
      'temporal-namespace': namespace,
      'authorization': `Bearer ${apiKey}`,
    },
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'progress-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  console.log('Worker started');
  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

